"""
MKT Original Language Commentary — Romans chapters 1–3
Run: python3 scripts/zc-original-romans-1-3.py

Source data used:
- data/interlinear/romans.json
- data/translation/glossary-greek.json
- data/translation/draft/mediating/romans.json (MKT text for quoting)
- data/translation/notes/romans.json
- data/commentary/mkt-original/john.json (style reference)

Key philological decisions in this range:
- 1:1 doulos = slave, not servant; aphorismenon echoes Pharisee root
- 1:4 horisthentos = declared/designated, not predestined; the perfect tense matters
- 1:17 dikaiosyne theou — genitive of source and character, not merely authored-by;
  the ek pisteos eis pistin construction left intentionally open (from faithfulness to faith)
- 1:18 apokalypto in present passive = active ongoing revelation; katecho = actively suppress
- 1:24/26/28 paredoken — three judicial hand-overs, active verb, not passive withdrawal
- 2:14 physei = by nature; the dative of manner, not by birth
- 3:21 nuni de — temporal and logical hinge; choris nomou = apart from law entirely
- 3:22 pisteos Iesou Christou — the subjective/objective genitive debate addressed;
  MKT uses "faith in Christ" but the subjective reading (faithfulness of Christ) is noted
- 3:24 dorean = as a free gift / gratis / without cost to the recipient
- 3:25 hilasterion — its background in the kapporeth (mercy seat) of Exod 25:17 / Lev 16
  is the primary reference; propitiation and expiation are both present
- 3:26 dikaioun ton ek pisteos — the one-who-justifies language is forensic acquittal,
  not merely moral improvement; the present active participle = continual activity
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "1": {
    "1": '<p><strong>δοῦλος</strong> (<em>doulos</em>) — the standard English translation "servant" understates the Greek: a <em>doulos</em> is a slave, one who belongs entirely to the master. Paul places this self-designation first, before "apostle," making total ownership by Christ the ground of his commission rather than its limitation.</p><p><strong>ἀφωρισμένος</strong> (<em>aphorismenon</em>) — "set apart," perfect passive participle. The same root as <em>Pharisee</em> (perushim, the separated ones). Paul the former Pharisee has been re-separated — not from Gentile contamination but for the gospel. The word signals a deliberate reorientation of his prior separatist vocation.</p>',
    "2": '<p><strong>προεπηγγείλατο</strong> (<em>proepēngeilato</em>) — "promised beforehand," aorist middle of <em>proepangellomai</em>. The <em>pro-</em> prefix is emphatic: the gospel is not new but the fulfillment of prior divine commitment. The agent is God; the medium is "his prophets in the holy scriptures" — <em>graphais hagiais</em>, which identifies the OT as a single unified text of sacred promise.</p>',
    "3": '<p><strong>κατὰ σάρκα</strong> (<em>kata sarka</em>) — "according to the flesh" — the preposition <em>kata</em> with the accusative denotes the sphere or standard of measurement. The Davidic descent is real and historical but belongs to the sphere of natural descent; v4 will supply the contrasting sphere.</p>',
    "4": '<p><strong>ὁρισθέντος</strong> (<em>horisthentos</em>) — aorist passive participle of <em>horizō</em>, "to mark off, designate, declare." The NKJV "declared" is preferable to "predestined" here; Paul is not speaking of an eternal decree but of the resurrection as a public declaration that Jesus is who he claimed to be. The aorist points to the single historical event of the resurrection as the moment of declaration.</p><p><strong>ἐξ ἀναστάσεως νεκρῶν</strong> — "by resurrection from the dead" (genitive of means). The resurrection is not merely what happened to Jesus but the revelatory event that declared his identity <em>with power</em> (<em>en dynamei</em>). The power-phrase modifies the Son-of-God designation, not the resurrection itself: he was declared Son-of-God-in-power by means of the resurrection.</p>',
    "5": '<p><strong>χάριν καὶ ἀποστολήν</strong> (<em>charin kai apostolēn</em>) — "grace and apostleship." The <em>kai</em> here may be explanatory ("grace, specifically apostleship") rather than additive — the apostolic commission is itself a form of grace. The goal: <strong>ὑπακοὴν πίστεως</strong> (<em>hypakoēn pisteōs</em>) — "obedience of faith," a genitive of apposition (the obedience that consists in faith) or of source (the obedience that flows from faith); both are true.</p>',
    "6": '<p><strong>κλητοὶ Ἰησοῦ Χριστοῦ</strong> (<em>klētoi Iēsou Christou</em>) — "called of/belonging to Jesus Christ," genitive of possession. The letter\'s audience is defined by their relationship to Christ through divine calling, not by ethnicity or prior religious affiliation. The <em>klētos</em> (called) root recurs in v7 ("called to be saints") and forms an inclusio with v1 ("called to be an apostle").</p>',
    "7": '<p><strong>κλητοῖς ἁγίοις</strong> (<em>klētois hagiois</em>) — "called saints" — not aspirationally holy but constitutively designated. The participle is a verbal adjective: they are saints because they are called, not called because they are already saintly. <strong>χάρις</strong> and <strong>εἰρήνη</strong> (<em>charis kai eirēnē</em>) — the Pauline greeting replaces the standard Greek <em>chairein</em> (greetings) with <em>charis</em> (grace), and adds the Hebrew <em>shalom</em> (peace) — a fusion of Greco-Roman and Jewish greeting forms that announces the letter\'s cross-cultural address.</p>',
    "8": '<p><strong>ἡ πίστις ὑμῶν</strong> (<em>hē pistis hymōn</em>) — "your faith," with the definite article emphasizing the particular character of the Roman community\'s reputation. <strong>καταγγέλλεται</strong> (<em>katangelletai</em>) — present passive, "is being proclaimed/announced" — the gospel-proclamation verb used of the good news; the Roman church\'s faith is itself a form of proclamation throughout the known world.</p>',
    "9": '<p><strong>λατρεύω</strong> (<em>latreuō</em>) — "serve as a priest" or "render cultic service." Paul describes his prayer life with the vocabulary of temple service, placing intercessory prayer within the framework of priestly ministry. <strong>ἐν τῷ πνεύματί μου</strong> — "in my spirit" — the locus of Paul\'s gospel service is interior, not in the external rites of the temple cult.</p>',
    "10": '<p><strong>εὐοδωθήσομαι</strong> (<em>euodōthēsomai</em>) — "to be prospered/given a good road" (<em>odos</em> = road, <em>eu-</em> = good). The travel metaphor is embedded in the word itself. Paul frames his desire to visit Rome as a petition for God to give him the right road — a combination of circumstantial opportunity and divine guidance.</p>',
    "11": '<p><strong>μεταδῶ χάρισμά τι πνευματικόν</strong> (<em>metadō charisma ti pneumatikon</em>) — "to share some spiritual gift." The indefinite <em>ti</em> ("some") is tactfully vague — Paul does not specify what gift he would bring, likely to avoid appearing presumptuous with a community he has not founded.</p>',
    "12": '<p><strong>συμπαρακληθῆναι</strong> (<em>symparaklēthēnai</em>) — "to be mutually encouraged together" — the <em>syn-</em> prefix makes the encouragement reciprocal; Paul revises his v11 statement from one-directional giving to mutual benefit. The verb\'s root is <em>paraklēsis</em> (comfort/exhortation), showing that even the apostle expects to receive from the community rather than only imparting.</p>',
    "13": '<p><strong>τινα καρπὸν σχῶ</strong> (<em>tina karpon schō</em>) — "that I might have some fruit" — the aorist subjunctive indicates Paul\'s goal-orientation. The fruit-metaphor for missionary results is consistent with Paul\'s agricultural imagery elsewhere (1 Cor 3:6-9; Col 1:6). <strong>καθὼς καὶ ἐν τοῖς λοιποῖς ἔθνεσιν</strong> — "as also among the rest of the Gentiles" — Paul includes Rome in his Gentile mission-field, perhaps a delicate claim given Rome\'s mixed Jewish-Gentile community.</p>',
    "14": '<p><strong>Ἕλλησίν τε καὶ βαρβάροις</strong> (<em>Hellēsin te kai barbarois</em>) — "to Greeks and to barbarians." The Greek world divided all humanity into those who spoke Greek and those whose speech sounded like "bar-bar" (unintelligible noise). Paul\'s commission covers both cultural categories — the civilized and the uncivilized. <strong>σοφοῖς τε καὶ ἀνοήτοις</strong> — "to the wise and to the foolish" — a second axis covering intellectual status: educated and uneducated alike are Paul\'s debtors.</p>',
    "15": '<p><strong>πρόθυμον</strong> (<em>prothymon</em>) — "eager/ready," from <em>pro-thymos</em> (forward-minded, with forward spirit). The eagerness Paul claims is not reluctant duty but genuine missionary desire. The present infinitive <em>euangelisasthai</em> indicates not a one-time act but an ongoing readiness to proclaim.</p>',
    "16": '<p><strong>οὐ γὰρ ἐπαισχύνομαι</strong> (<em>ou gar epaischunomai</em>) — "for I am not ashamed" — the negated litotes (understatement) = Paul is positively proud of and committed to the gospel. In Roman honor-shame culture, the crucifixion was a symbol of shame; Paul\'s non-shame is a deliberate inversion. <strong>εἰς σωτηρίαν</strong> (<em>eis sōtērian</em>) — "unto salvation" — the purpose clause: power exercised for a goal, not power for display. <strong>Ἰουδαίῳ τε πρῶτον καὶ Ἕλληνι</strong> — "to the Jew first and also to the Greek" — the priority is historical-redemptive (Jew first = covenant priority) not chronologically mandatory for each city, as Paul\'s own practice varied.</p>',
    "17": '<p><strong>δικαιοσύνη θεοῦ</strong> (<em>dikaiosynē theou</em>) — the most debated genitive in Paul. Grammatically it can be: (a) God\'s attribute ("God\'s own righteousness"), (b) a righteousness God gives ("righteousness from God"), or (c) God\'s faithfulness to his covenant. Paul\'s usage across Romans suggests all three overlap: God\'s own righteousness is given as gift through the covenant faithfulness demonstrated in Christ.</p><p><strong>ἐκ πίστεως εἰς πίστιν</strong> (<em>ek pisteōs eis pistin</em>) — "from faith to faith." The doubled construction has been read as: (a) from beginning faith to mature faith (progressive), (b) from the faithfulness of God/Christ to the faith of the believer (movement from source to recipient), or (c) from faith alone to faith alone (emphatic). The phrase resists reduction to a single interpretation; Paul may be intentionally layered.</p>',
    "18": '<p><strong>ἀποκαλύπτεται</strong> (<em>apokalypto</em>) — present passive indicative, "is being revealed" — the same verb used of the gospel\'s revelation in v17. Both grace and wrath are being revealed simultaneously in the present age through the gospel. The wrath of God is not a future reality only but an active present disclosure, observable in the consequences of human rebellion (vv19-32).</p><p><strong>κατεχόντων</strong> (<em>katechontōn</em>) — present active participle of <em>katechō</em>, "to hold down, suppress." Not passive ignorance but active suppression: the truth is grasped and then held under. The moral failure described is deliberate, making the charge of suppression rather than mere ignorance fundamental to Paul\'s indictment.</p>',
    "19": '<p><strong>φανερόν</strong> (<em>phaneron</em>) — "manifest, visible, clear" — the divine disclosure through creation is not obscure or requiring special illumination; it is simply there to be seen. <strong>ἐν αὐτοῖς</strong> (<em>en autois</em>) — "in them/among them" — the manifestation is not only external (in creation) but internal (written in the conscience, cf. 2:15); the duality of the knowledge makes the suppression all the more culpable.</p>',
    "20": '<p><strong>ἀόρατα</strong> (<em>aorata</em>) — "invisible things," the neuter plural. The invisible attributes are made visible through the visible creation — the paradox is intentional. <strong>ἀΐδιος δύναμις</strong> (<em>aidios dynamis</em>) — "eternal power" — <em>aidios</em> (eternal) is Paul\'s only use of this word; it is emphatic for the quality that distinguishes divine power from all created power. <strong>θειότης</strong> (<em>theiotēs</em>) — "divine nature/divinity" — a different word from <em>theotēs</em> (Godhead, used in Col 2:9); <em>theiotēs</em> refers to the quality of being divine rather than the full personal reality of the Godhead. <strong>ἀναπολογήτους</strong> (<em>anapologētous</em>) — "without defense, without excuse" — a forensic term; the courtroom image is already present in v18\'s wrath-language.</p>',
    "21": '<p><strong>ἐματαιώθησαν</strong> (<em>emataiōthēsan</em>) — aorist passive, "became futile/vain" — the same root as LXX <em>mataiotes</em> (vanity/futility) in Ecclesiastes; Paul describes the darkened mind as the consequence of refusing to honor God. The passive may be a divine passive: they were made futile — not merely that they chose futility but that God ratified their choice.</p><p><strong>ἡ ἀσύνετος αὐτῶν καρδία</strong> (<em>hē asynchetos kardia</em>) — "their foolish/without-understanding heart." In Jewish anthropology, the <em>kardia</em> is the center of the whole person: will, intellect, and emotion together. The darkening of the heart is the darkening of the entire center of the self, not merely an intellectual error.</p>',
    "22": '<p><strong>φάσκοντες εἶναι σοφοί</strong> (<em>phasontes einai sophoi</em>) — "claiming to be wise" — the present participle describes an ongoing self-designation. The claim to philosophical wisdom (sophia) was the marker of Greco-Roman intellectual culture; Paul\'s indictment targets the highest cultural achievement of the pagan world, not its lowest.</p>',
    "23": '<p><strong>ἤλλαξαν τὴν δόξαν</strong> (<em>ēllaxan tēn doxan</em>) — "they exchanged the glory" — the aorist active: a definitive act of substitution. The glory that belongs to the incorruptible God is traded for images of corruptible creatures. The exchange-structure (<em>ēllaxan</em> in v23, <em>metēllaxan</em> in vv25-26) frames the moral analysis of the fall.</p>',
    "24": '<p><strong>παρέδωκεν αὐτοὺς ὁ θεός</strong> (<em>paredoken autous ho theos</em>) — "God gave them over" — the first of three judicial hand-overs (vv24, 26, 28). The aorist active of <em>paradidōmi</em> ("hand over") is not divine passivity (looking away) but active judicial decision: God delivers the rebels into the consequences of their own choice. The same verb describes Christ being handed over to death (4:25; 8:32) — the divine act that operates in both judgment and redemption.</p>',
    "25": '<p><strong>μετήλλαξαν τὴν ἀλήθειαν τοῦ θεοῦ ἐν τῷ ψεύδει</strong> (<em>metēllaxan tēn alētheian tou theou en tō pseudei</em>) — "they exchanged the truth of God for a lie." The exchange completes the pattern of v23: glory exchanged → now truth exchanged. <strong>ἐν τῷ ψεύδει</strong> — "in/for the lie" — the article <em>tō</em> is notable: not "a lie" but "the lie," suggesting a particular falsehood — the lie of idolatry that claims the creature deserves the Creator\'s honor.</p>',
    "26": '<p><strong>παρέδωκεν αὐτοὺς ὁ θεός</strong> — second occurrence. The repetition of the judicial hand-over formula is structural: Paul traces the escalating consequence of the fall through three stages, each introduced by this phrase. The second stage concerns sexual disorder as both consequence and expression of the inversion of creation order.</p><p><strong>φυσικὴν χρῆσιν</strong> (<em>physikēn chrēsin</em>) — "natural use" — <em>physis</em> (nature) in Paul typically means the created order as established by God, not individual inclination. The argument is from creation-design rather than from cultural convention.</p>',
    "27": '<p><strong>ἐξεκαύθησαν ἐν τῇ ὀρέξει αὐτῶν</strong> (<em>exekauthēsan en tē orexei autōn</em>) — "burned in their desire/craving" — the aorist passive of <em>ekkaiō</em> (to set ablaze) conveys consuming intensity. <strong>τὴν ἀντιμισθίαν ἣν ἔδει τῆς πλάνης αὐτῶν</strong> — "the due penalty of their error" — <em>antimisthia</em> (due return, counter-payment) frames the consequence as a moral-cosmic exchange; what they receive is proportional to and appropriate to their departure.</p>',
    "28": '<p><strong>παρέδωκεν αὐτοὺς ὁ θεός</strong> — third occurrence, completing the structure. <strong>εἰς ἀδόκιμον νοῦν</strong> (<em>eis adokimon noun</em>) — "into a disqualified/reprobate mind" — <em>adokimos</em> (failing the test, disqualified) is a metallurgical term for metal that does not pass the assay test. The mind that refuses to acknowledge God becomes a mind that cannot reliably distinguish moral categories.</p>',
    "29": '<p>The vice list in vv29-31 uses four different Greek constructions: (1) <strong>πεπληρωμένους</strong> (<em>peplērōmenous</em>) — "filled with," perfect passive participle, indicating a settled state; (2) simple nouns in the dative (vv29-31); (3) the <strong>-ους</strong> suffix adjectives indicating character-type (v29: <em>ponēria, pleonexia, kakia</em>); and (4) the <strong>ψιθυριστάς / καταλάλους</strong> agent-nouns (v29-30 — "whisperers, slanderers"). The formal variety signals that Paul is not listing mechanically but composing rhetorically.</p>',
    "30": '<p><strong>θεοστυγεῖς</strong> (<em>theostygeis</em>) — "haters of God" or "hated by God." The compound is rare; its active versus passive meaning is debated. The context (a list of human vices) favors "God-haters" — those who actively despise the God they have suppressed (v18). <strong>ὑπερηφάνους</strong> (<em>hyperēphanous</em>) — "arrogant, haughty" — literally "one who appears above others" (<em>hyper-phainō</em>); the social posturing of pride that appropriates divine prerogative.</p>',
    "31": '<p><strong>ἀσυνέτους</strong> (<em>asynchētous</em>) — "without understanding" — same root as the darkened heart of v21; the disqualified mind of v28 now expresses itself in specific moral categories. <strong>ἀσυνθέτους</strong> (<em>asynchetous</em>) — "covenant-breakers, untrustworthy" — literally "without-agreement," those who do not keep their pledged word; social trust collapses when the created order\'s truth is suppressed.</p>',
    "32": '<p><strong>τὸ δικαίωμα τοῦ θεοῦ</strong> (<em>to dikaiōma tou theou</em>) — "the righteous decree/ordinance of God" — not merely a moral intuition but a recognized standard; the pagans know the divine verdict that such practices are death-worthy. <strong>οὐ μόνον αὐτὰ ποιοῦσιν</strong> — "they not only practice them" — the aggravating factor is <strong>συνευδοκοῦσιν</strong> (<em>syneudokousin</em>) — "they also approve of/applaud" those who do them. The moral dysfunction has become cultural: the vice is celebrated, not merely committed.</p>'
  },
  "2": {
    "1": '<p><strong>ὦ ἄνθρωπε πᾶς ὁ κρίνων</strong> (<em>ō anthrōpe pas ho krinōn</em>) — "O man, every one who judges" — the vocative <em>ō</em> is rhetorical, addressing a generic figure (the moralistic judge). Paul does not yet specify Jew or Gentile, though the argument progressively reveals he has the morally self-confident Jew particularly in mind by vv17-20. <strong>ἀναπολόγητος</strong> — "without defense" — the same word as 1:20; the judge who condemns others on the basis of the knowledge that he himself suppresses is equally without excuse.</p>',
    "2": '<p><strong>κρίμα τοῦ θεοῦ</strong> (<em>krima tou theou</em>) — "judgment of God" — a judicial noun (<em>krima</em> = the act of judging, or the verdict rendered). <strong>κατὰ ἀλήθειαν</strong> (<em>kata alētheian</em>) — "according to truth" — God\'s judgment is measured against truth (the standard he himself is), not against the self-defined moral systems of the judge; the contrast with human hypocrisy is built into the standard.</p>',
    "3": '<p><strong>λογίζῃ</strong> (<em>logizē</em>) — "do you reckon/calculate?" — the same forensic term Paul uses in 3:28 and 4:3-8 for imputation. Here it is ironic: the judge is calculating/reasoning incorrectly about divine judgment, imagining that moral posturing exempts from the verdict that comes on those who do the same things.</p>',
    "4": '<p><strong>χρηστότητος</strong> (<em>chrēstotētos</em>), <strong>ἀνοχῆς</strong> (<em>anochēs</em>), <strong>μακροθυμίας</strong> (<em>makrothymias</em>) — three distinct Greek terms for divine patience: (1) <em>chrēstotēs</em> = kindness, moral goodness in disposition; (2) <em>anochē</em> = forbearance, the restraint of wrath that could be exercised; (3) <em>makrothymia</em> = long-suffering, enduring capacity not to retaliate. Their accumulation signals that Paul is not using synonyms loosely but cataloguing the specific qualities of divine patience.</p><p><strong>εἰς μετάνοιαν</strong> (<em>eis metanoian</em>) — "toward repentance" — the purpose of divine kindness is the behavioral-and-cognitive turning that <em>metanoia</em> denotes (meta = after, noia = mind; the after-mind, the changed perspective that produces changed conduct).</p>',
    "5": '<p><strong>σκληρότητα καὶ ἀμετανόητον καρδίαν</strong> (<em>sklērotēta kai ametanoēton kardian</em>) — "hardness and unrepentant heart" — <em>sklērotēs</em> (hardness) echoes the OT hardening of Pharaoh\'s heart; <em>ametanoētos</em> (unrepentant) is Paul\'s only use of this adjective. The irony is that the one who calls others to repentance has an unrepentant heart. <strong>ὀργῆς</strong> (<em>orgēs</em>) — "wrath" — the day of wrath is a treasury being accumulated by every act of unrepentant hardness: <em>θησαυρίζεις</em> (<em>thēsaurizeis</em>) = "you are treasuring up" (present active), an active storing of future judgment.</p>',
    "6": '<p><strong>ἀποδώσει ἑκάστῳ κατὰ τὰ ἔργα αὐτοῦ</strong> (<em>apodōsei hekastō kata ta erga autou</em>) — "he will render to each according to his works" — the future active of <em>apodidōmi</em> (to give back what is owed). The standard is individual works rather than group membership. Paul is not setting up a works-salvation principle that will later be qualified by grace; he is first establishing that God\'s judgment is impartial and individual, which is essential before revealing that none can meet the standard (3:20).</p>',
    "7": '<p><strong>ζητοῦσιν δόξαν καὶ τιμὴν καὶ ἀφθαρσίαν</strong> (<em>zētousin doxan kai timēn kai aphtharsian</em>) — "seeking glory and honor and immortality" — the three nouns move from present experience to future reality. <em>Aphtharsian</em> (incorruptibility) is the eschatological dimension: the transformed body not subject to the decay of the present creation. Paul\'s description of eternal life (v7) is emphatically concrete and embodied.</p>',
    "8": '<p><strong>ἐξ ἐριθείας</strong> (<em>ex eritheias</em>) — "from selfish ambition" — <em>eritheia</em> originally meant "work for hire" and came to denote the motivation of mercenary self-seeking; it appears in the vice lists of Gal 5:20 and Phil 2:3. Those characterized by it are contrasted with those who seek glory (v7) — the moral contrast is between self-seeking and God-seeking as the organizing principle of one\'s life.</p>',
    "9": '<p><strong>Ἰουδαίῳ τε πρῶτον καὶ Ἕλληνι</strong> — the Jew-first priority in v16 (grace) is now applied to tribulation: covenant privilege brings covenant accountability. The <em>prōton</em> (first) is symmetrical — the primacy is in both directions, which is why Paul says it in both 1:16 and 2:9-10.</p>',
    "10": '<p><strong>δόξα δὲ καὶ τιμὴ καὶ εἰρήνη</strong> (<em>doxa de kai timē kai eirēnē</em>) — the three goods of v7 (glory, honor) are repeated with <em>eirēnē</em> (peace) substituted for <em>aphtharsian</em> (immortality); peace is the present-tense experience of what immortality will complete. The parallel structuring of vv9-10 by the repeated <em>Ἰουδαίῳ τε πρῶτον καὶ Ἕλληνι</em> reinforces the impartiality principle.</p>',
    "11": '<p><strong>προσωπολημψία</strong> (<em>prosōpolēmpsia</em>) — "face-taking" — a Hebrew idiom (nasa panim = lift the face toward someone in favor) translated into Greek. The divine impartiality Paul asserts is a direct echo of Deut 10:17 ("the LORD your God does not show favoritism") applied now to Jewish-Gentile distinctions in divine judgment.</p>',
    "12": '<p><strong>ἀνόμως ἥμαρτον, ἀνόμως καὶ ἀπολοῦνται</strong> (<em>anomōs hēmarton, anomōs kai apolountai</em>) — "sinned without law... will perish without law." The <em>anōmos</em> / <em>en nomō</em> contrast structures the principle of judgment by the available standard. Gentiles are not judged against a law they did not have; they are judged by what they did have (the natural law of vv14-15).</p>',
    "13": '<p><strong>ποιηταὶ νόμου δικαιωθήσονται</strong> (<em>poiētai nomou dikaiōthēsontai</em>) — "doers of the law will be justified." The future passive of <em>dikaioō</em> is forensic: declared righteous at the eschatological judgment. Paul is stating the principle of Lev 18:5 seriously before showing in 3:9-20 that no one is actually such a doer; the principle stands but the actuality refutes all claimants.</p>',
    "14": '<p><strong>φύσει</strong> (<em>physei</em>) — "by nature" — a dative of manner, not dative of origin (not "by birth" but "by the nature of things"). Gentiles who do instinctively what the law requires demonstrate that natural moral knowledge exists independently of Sinai\'s revelation. <strong>ἑαυτοῖς εἰσιν νόμος</strong> (<em>heautois eisin nomos</em>) — "they are a law to themselves" — not moral relativism but the affirmation that the law\'s normative claim is written into human nature.</p>',
    "15": '<p><strong>συνειδήσεως</strong> (<em>syneidēseōs</em>) — "conscience" — from <em>syn-oida</em> (to know together with); the conscience is the faculty of co-knowing, the internal witness that evaluates one\'s own actions by a shared moral standard. <strong>τῶν λογισμῶν κατηγορούντων ἢ καὶ ἀπολογουμένων</strong> — "the thoughts accusing or defending" — the forensic vocabulary (accuse/defend) is explicit: the conscience conducts an interior trial.</p>',
    "16": '<p><strong>ἐν ᾗ ἡμέρᾳ</strong> (<em>en hē hēmera</em>) — "on the day when" — the relative clause connects back to v13\'s principle; the justification of v13 will occur at the eschatological judgment. <strong>διὰ Χριστοῦ Ἰησοῦ</strong> — "through Christ Jesus" — the divine judge of the secrets of humanity operates through the mediatorial agency of Christ, unexpected in the context of universal moral judgment but consistent with Paul\'s Christological totality.</p>',
    "17": '<p><strong>Ἰουδαῖος ἐπονομάζῃ</strong> (<em>Ioudaios eponomazē</em>) — "you call yourself a Jew" — the present middle indicative; the self-designation is a claim being made repeatedly. From vv17-20 Paul lists five privileges the Jew claims: (1) the name/identity, (2) reliance on Torah, (3) boasting in God, (4) knowing God\'s will, (5) discerning what matters. The list sets up the irony of vv21-24.</p>',
    "18": '<p><strong>δοκιμάζεις τὰ διαφέροντα</strong> (<em>dokimazeis ta diapheronta</em>) — "you approve/discern what matters" — <em>dokimazō</em> is the testing/assaying term (see 1:28); <em>ta diapheronta</em> can mean "the things that differ" (distinguishing between options) or "the things that are superior" (preferring what matters). The ambiguity is likely intentional: the instruction of the law provides both distinction and prioritization.</p>',
    "19": '<p><strong>ὁδηγὸν εἶναι τυφλῶν</strong> (<em>hodēgon einai typhlōn</em>) — "a guide to the blind" — <em>hodēgos</em> = road-guide (hodos + agō). The claim echoes Isa 42:6-7 (the Servant as a light to the blind and a covenant to the nations); Paul uses the self-designation of the Servant to describe the Jew\'s self-understanding, setting up the irony that the guide needs guiding.</p>',
    "20": '<p><strong>μορφωσιν τῆς γνώσεως καὶ τῆς ἀληθείας</strong> (<em>morphōsin tēs gnōseōs kai tēs alētheias</em>) — "the form of knowledge and truth" — <em>morphōsis</em> denotes the external shape or appearance of something; Paul\'s choice of this word is already critical: the law gives the Jewish teacher an external form (<em>morphōsis</em>) of knowledge without necessarily the inner reality (<em>morphē</em> would be the real form).</p>',
    "21": '<p><strong>κηρύσσων μὴ κλέπτειν κλέπτεις</strong> (<em>kēryssōn mē kleptein klepteis</em>) — "you who preach not to steal, do you steal?" — the present active participle (preaching) paired with the present indicative (stealing) creates the indictment of simultaneous proclamation and violation. The preacher-thief is not hypothetical but representative of a recognized pattern in Paul\'s indictment.</p>',
    "22": '<p><strong>βδελυσσόμενος τὰ εἴδωλα ἱεροσυλεῖς</strong> (<em>bdelyssomenos ta eidōla hierosyleis</em>) — "you who abhor idols, do you rob temples?" — <em>hierosyleis</em> (to rob a temple) could refer to literal sacrilege (looting pagan shrines while professing to detest idolatry) or to the broader spiritual idolatry of covetousness Paul will address elsewhere. Either way, the verbal irony is sharp.</p>',
    "23": '<p><strong>νόμου παράβασις</strong> (<em>nomou parabasis</em>) — "transgression of the law" — <em>parabasis</em> (stepping alongside, stepping past) is more deliberate than mere failure (<em>hamartia</em>); it implies knowing the boundary and crossing it intentionally. This is the specific accusation: not ignorance of the law but active violation of the law one claims to teach.</p>',
    "24": '<p><strong>τὸ γὰρ ὄνομα τοῦ θεοῦ δι᾽ ὑμᾶς βλασφημεῖται</strong> — "for the name of God is blasphemed among the Gentiles because of you" — a quotation from LXX Isa 52:5 (cf. Ezek 36:20-22). The present passive <em>blasphēmeitai</em> indicates an ongoing reality, not a historical incident; the Jewish community\'s covenant violations have become a sustained cause of Gentile contempt for the God who claims them.</p>',
    "25": '<p><strong>περιτομὴ μὲν γὰρ ὠφελεῖ</strong> (<em>peritomē men gar ōphelei</em>) — "circumcision benefits" — Paul affirms the real value of circumcision before qualifying it; the <em>men gar</em> construction acknowledges genuine advantage. <strong>ἐὰν νόμον πράσσῃς</strong> — "if you practice the law" — the conditional shifts the benefit from the rite itself to the covenantal obedience it signs; the sign without the signified reality is null.</p>',
    "26": '<p><strong>ἡ ἀκροβυστία αὐτοῦ εἰς περιτομὴν λογισθήσεται</strong> (<em>hē akrobystia autou eis peritomēn logisthēsetai</em>) — "his uncircumcision will be reckoned as circumcision" — <em>logizō</em> again: the forensic reckoning that counts uncircumcision as circumcision when covenant faithfulness is present. Paul applies the same reckoning-logic he will use for Abraham\'s faith in ch4 to the Gentile who keeps the law\'s requirements.</p>',
    "27": '<p><strong>κρινεῖ</strong> (<em>krinei</em>) — future active, "will judge" — the eschatological scenario: the obedient Gentile standing as a judge over the disobedient, law-possessing Jew. The reversal echoes the OT tradition of Nineveh\'s repentance condemning Israel (Matt 12:41); external markers of covenant membership without covenant faithfulness cannot survive the judgment.</p>',
    "28": '<p><strong>ἐν τῷ κρυπτῷ Ἰουδαῖος</strong> (<em>en tō kryptō Ioudaios</em>) — "in the hidden Jew" — <em>kryptos</em> (hidden, inward) contrasts with the external/visible (<em>phaneros</em>, v28). Paul\'s paradox: the real Jew is the one who is a Jew in the hidden, interior reality — a formulation that both affirms Jewish particularity and universalizes it by grounding Jewishness in the inward reality that the covenant was always aimed at (Deut 30:6 — circumcision of the heart).</p>',
    "29": '<p><strong>περιτομὴ καρδίας ἐν πνεύματι οὐ γράμματι</strong> (<em>peritomē kardias en pneumati ou grammati</em>) — "circumcision of heart, in Spirit not letter" — the <em>pneuma/gramma</em> (spirit/letter) antithesis Paul will develop in 7:6 and 2 Cor 3:6. The circumcision the OT promises (Deut 30:6; Jer 4:4; Ezek 36:26-27) is the interior reality of which the external rite is a sign. <strong>ἔπαινος οὐκ ἐξ ἀνθρώπων ἀλλ᾽ ἐκ τοῦ θεοῦ</strong> — praise from God rather than humans is the ultimate validation — a direct inversion of the honor-shame framework that makes human praise the measure of worth.</p>'
  },
  "3": {
    "1": '<p><strong>τί οὖν τὸ περισσὸν τοῦ Ἰουδαίου</strong> (<em>ti oun to perisson tou Ioudaiou</em>) — "what then is the advantage of the Jew?" — Paul shifts to a diatribal interlocutor. <em>Perisson</em> means "excess, advantage, surplus" — the same root as <em>perisseuo</em> (to abound). The question acknowledges that the argument of ch2 might seem to eliminate Jewish advantage entirely; Paul will affirm real advantage before qualifying it.</p>',
    "2": '<p><strong>ἐπιστεύθησαν τὰ λόγια τοῦ θεοῦ</strong> (<em>episteuthēsan ta logia tou theou</em>) — "they were entrusted with the oracles of God" — the aorist passive of <em>pisteuō</em> (to believe/entrust); the same word-family as faith but in the trust-deposit sense. <em>Logia</em> (oracles) is a term for divine utterances, particularly prophetic speech. The advantage is not ethnicity but covenant revelation: having been entrusted with God\'s own words.</p>',
    "3": '<p><strong>ἡ ἀπιστία αὐτῶν τὴν πίστιν τοῦ θεοῦ καταργήσει</strong> (<em>hē apistia autōn tēn pistin tou theou katargēsei</em>) — "will their unbelief nullify God\'s faithfulness?" — <em>apistia</em> (unbelief/unfaithfulness) contrasted with <em>pistis tou theou</em> (faithfulness of God). The genitive <em>tou theou</em> here is clearly subjective: God\'s own faithfulness/trustworthiness. <em>Katargeō</em> — "to render inoperative, nullify" — a strong verb Paul uses for the abolition of the law and the nullification of Christ (Gal 5:4).</p>',
    "4": '<p><strong>γινέσθω δὲ ὁ θεὸς ἀληθής</strong> (<em>ginesthō de ho theos alēthēs</em>) — "let God be true" — the imperative <em>ginesthō</em> (become/let-be) does not mean God is not yet true but is the rhetorical assertion of the absolute: even if (hypothetically) all humans were liars, God\'s truth stands unaffected. <strong>ὅπως ἂν δικαιωθῇς ἐν τοῖς λόγοις σου</strong> — quoting LXX Ps 51:4: "that you may be justified in your words" — the psalmist\'s confession that God is right when he judges applies to the present argument.</p>',
    "5": '<p><strong>τί ἐροῦμεν; μὴ ἄδικος ὁ θεός</strong> (<em>ti eroumen; mē adikos ho theos</em>) — "what shall we say? Is God unjust?" — the interlocutor\'s reductio: if my injustice displays God\'s righteousness, how can God judge me? Paul identifies the reasoning immediately as distinctively human (<em>κατὰ ἄνθρωπον λέγω</em> — "I speak as a human being"). The objection is logically coherent but morally absurd.</p>',
    "6": '<p><strong>ἐπεὶ πῶς κρινεῖ ὁ θεὸς τὸν κόσμον</strong> — "since how will God judge the world?" — the rhetorical appeal to universal divine judgment as self-evident: if God cannot judge fairly, the entire structure of biblical theodicy collapses. The world\'s judgment as God\'s prerogative is so foundational that the objection refutes itself.</p>',
    "7": '<p><strong>ἐν τῷ ἐμῷ ψεύσματι</strong> (<em>en tō emō pseudismati</em>) — "through my lie" — Paul continues the diatribal exchange, now pushing the logic to its most absurd conclusion: if my falsehood increases God\'s truth-display, I should be more praised, not condemned. The <em>ema</em> (my own) is emphatic: this is the interlocutor\'s own reasoning about his own falsehood.</p>',
    "8": '<p><strong>ποιήσωμεν τὰ κακὰ ἵνα ἔλθῃ τὰ ἀγαθά</strong> — "let us do evil that good may come" — this is not Paul\'s teaching but the slander leveled against Paul\'s gospel of grace; some were evidently claiming that his teaching logically implied moral libertinism. <strong>ὧν τὸ κρίμα ἔνδικόν ἐστιν</strong> — "whose condemnation is just" — <em>endikos</em> (in-right, just) pronounces the condemnation fitting by the law\'s own standard.</p>',
    "9": '<p><strong>οὐ πάντως</strong> (<em>ou pantōs</em>) — "not at all / not entirely." The phrase is debated: does Paul say Jews have "no advantage at all" (contradicting v2) or "no advantage in every respect"? Given v2\'s "much in every way," Paul likely means "no decisive advantage for the purpose of avoiding condemnation" — not a flat denial of all Jewish advantage.</p><p><strong>προῃτιασάμεθα</strong> (<em>proētiasametha</em>) — "we have already charged" — the perfect tense indicates the charge is established from prior argument; Paul now summarizes. The verb <em>aitiaō</em> is forensic: to bring a formal charge.</p>',
    "10": '<p>The catena of quotations in vv10-18 is a classical Jewish rhetorical technique of stringing OT texts together to make a cumulative point (cf. 4QFlor at Qumran). The individual quotations are from Ps 14/53; Ps 5:9; Ps 140:3; Ps 10:7; Isa 59:7-8; Ps 36:1 — spanning Psalms and Prophets to demonstrate that the indictment is not Pauline invention but Scripture\'s own verdict on universal human unrighteousness.</p>',
    "11": '<p><strong>οὐκ ἔστιν ὁ συνίων, οὐκ ἔστιν ὁ ἐκζητῶν τὸν θεόν</strong> — "there is none who understands, none who seeks God" — <em>syniōn</em> (understanding, from <em>synesis</em>) and <em>ekzētōn</em> (seeking out, intensive compound of <em>zēteō</em>). The double negation and the present participles make these absolute characterizations: understanding and God-seeking are entirely absent from human initiative in the natural state. Paul quotes Ps 14:2 LXX verbatim.</p>',
    "12": '<p><strong>πάντες ἐξέκλιναν</strong> (<em>pantes exeklinan</em>) — "all have turned aside" — the aorist active: a completed definitive turning. <em>Exklinō</em> (turn out from, deviate) is a navigational metaphor: everyone has gone off course. <strong>ἅμα</strong> (<em>hama</em>) — "together/at once" — universality is both numerical (all) and simultaneous (together), leaving no exception.</p>',
    "13": '<p><strong>τάφος ἀνεῳγμένος</strong> (<em>taphos aneōgmenos</em>) — "an open grave" — perfect passive participle: permanently open. The throat as an open grave is the image of consuming speech that destroys what it consumes; Ps 5:9 LXX provides this image. <strong>ἐδολιοῦσαν ταῖς γλώσσαις αὐτῶν</strong> (<em>edoliousan tais glōssais autōn</em>) — "with their tongues they were deceitful" — imperfect tense: ongoing habitual deceit. The speech-anatomy chain (throat, tongue, lips, mouth) moves from the largest organ to the smallest.</p>',
    "14": '<p><strong>οὗ τὸ στόμα ἀρᾶς καὶ πικρίας γέμει</strong> (<em>hou to stoma aras kai pikrias gemei</em>) — "whose mouth is full of cursing and bitterness" — the present active <em>gemei</em> (is full to the brim) indicates a saturated, overflowing condition; not occasional outburst but characteristic speech. From Ps 10:7 LXX.</p>',
    "15": '<p><strong>ὀξεῖς οἱ πόδες αὐτῶν ἐκχέαι αἷμα</strong> (<em>oxeis hoi podes autōn ekcheai haima</em>) — "their feet are swift to shed blood" — <em>oxys</em> (sharp, swift) describes a readiness that requires no deliberation; violence is the instinctive trajectory of the unrenewed will. From Isa 59:7-8 LXX, where the same indictment falls on Israel specifically.</p>',
    "16": '<p><strong>σύντριμμα καὶ ταλαιπωρία</strong> (<em>syntrimma kai talaipōria</em>) — "destruction and misery" — <em>syntrimma</em> (a crushing together, from <em>trib</em> = rubbing) is what the swift feet leave behind; the violence that the tongue and feet produce creates a trail of crushed and suffering people. The social consequences of universal unrighteousness are not abstract but embodied in human suffering.</p>',
    "17": '<p><strong>ὁδὸν εἰρήνης οὐκ ἔγνωσαν</strong> (<em>hodon eirēnēs ouk egnōsan</em>) — "the way of peace they have not known" — the aorist <em>egnōsan</em> (they knew) marks this as a definitively absent knowledge; shalom as the experience of right relationships (with God, self, neighbor, creation) is unknown to the unrighteous. The road imagery reinforces the navigational language of v12 (all turned aside).</p>',
    "18": '<p><strong>οὐκ ἔστιν φόβος θεοῦ ἀπέναντι τῶν ὀφθαλμῶν αὐτῶν</strong> (<em>ouk estin phobos theou apenanti tōn ophthalmōn autōn</em>) — "there is no fear of God before their eyes" — <em>phobos theou</em> (fear of God) is the OT term for the foundational orientation of wisdom and righteousness (Ps 111:10; Prov 1:7; 9:10). Its absence before their eyes is the summary diagnosis: the entire inner life is organized without reference to the holy God. Quoting Ps 36:1 LXX.</p>',
    "19": '<p><strong>ἵνα πᾶν στόμα φραγῇ</strong> (<em>hina pan stoma phragē</em>) — "that every mouth may be stopped" — aorist passive subjunctive of <em>phrassō</em> (to fence off, block); the closing of every mouth before God is the forensic consequence of the catena: the OT\'s own verdict leaves no room for self-defense. <strong>ὑπόδικος γένηται πᾶς ὁ κόσμος τῷ θεῷ</strong> — "that all the world may become accountable to God" — <em>hypodikos</em> = "under sentence, answerable to" (hypo = under; dikē = justice/judgment).</p>',
    "20": '<p><strong>ἐξ ἔργων νόμου οὐ δικαιωθήσεται πᾶσα σάρξ</strong> (<em>ex ergōn nomou ou dikaiōthēsetai pasa sarx</em>) — "from works of law no flesh will be justified" — the future passive declarative: the eschatological judgment will produce no acquittals on the basis of law-performance. <strong>πᾶσα σάρξ</strong> (<em>pasa sarx</em>) — "all flesh" — LXX idiom for every human being, emphasizing the frailty and mortality of the human creature before the holy God.</p><p><strong>διὰ γὰρ νόμου ἐπίγνωσις ἁμαρτίας</strong> (<em>dia gar nomou epignōsis hamartias</em>) — "for through the law comes knowledge of sin" — not <em>gnōsis</em> (knowledge) but <em>epignōsis</em> (full/accurate knowledge); the law does not merely inform about sin but produces a precise recognition of its character and extent. This is the law\'s true diagnostic function — not justification but conviction.</p>',
    "21": '<p><strong>νυνὶ δέ</strong> (<em>nyni de</em>) — "but now" — the most emphatic temporal hinge in the letter; the de (but/and) marks the adversative contrast with the law\'s inability (v20), and <em>nyni</em> (now) marks the new epoch. The disclosure of God\'s righteousness is both temporal (happening now in the present era) and logical (here is the alternative to works-of-law).</p><p><strong>χωρὶς νόμου</strong> (<em>chōris nomou</em>) — "apart from law" — not "against law" or "replacing law" but "independent of law as a mechanism of acquittal." The preposition <em>chōris</em> (apart from, without) is precise: the law is not the instrument through which this righteousness operates. <strong>μαρτυρουμένη</strong> (<em>marturoumenē</em>) — "being witnessed to" — present passive participle; the law and prophets are not being bypassed but are themselves bearing witness to what is now disclosed.</p>',
    "22": '<p><strong>πίστεως Ἰησοῦ Χριστοῦ</strong> (<em>pisteōs Iēsou Christou</em>) — the central syntactical debate: is this "faith in Jesus Christ" (objective genitive, the traditional reading) or "faithfulness of Jesus Christ" (subjective genitive, understanding Christ himself as the faithful one)? Grammatically both are possible; contextually Paul\'s consistent emphasis on the human act of believing (v22b: "to all who believe") favors the objective reading, but the subjective reading captures something theologically true (Christ\'s own faithfulness in obedience to death) that Paul develops in 5:12-21.</p>',
    "23": '<p><strong>πάντες γὰρ ἥμαρτον</strong> (<em>pantes gar hēmarton</em>) — "for all sinned" — aorist indicative: a single historical act encompassing all humanity. The aorist may point to the Adam-event (all sinned in Adam, 5:12) rather than merely to individual moral failures. <strong>ὑστεροῦνται τῆς δόξης τοῦ θεοῦ</strong> (<em>hysterounta tēs doxēs tou theou</em>) — "fall short of the glory of God" — present middle/passive, continuous state. The glory of God lost in Adam\'s fall is the OT background (<em>kebod yhwh</em>); Paul sees the present condition of humanity as the ongoing consequence of that original loss.</p>',
    "24": '<p><strong>δωρεὰν</strong> (<em>dōrean</em>) — "freely, as a gift, gratis." The adverb emphasizes that the justification costs the recipient nothing — it is entirely given without merit or payment on the receiver\'s part. Notably the same word appears in John 15:25 ("they hated me without reason") and John 1:16 ("grace upon grace"); <em>dōrean</em> means "at no cost" to the one receiving.</p><p><strong>ἀπολυτρώσεως</strong> (<em>apolytrōseōs</em>) — "redemption" — the <em>lytron</em> root means ransom price paid to secure release (of a slave or prisoner of war). The <em>apo-</em> prefix emphasizes the resultant freedom: the redemption that liberates. The price is specified in v25 (Christ\'s blood); the mechanism (the propitiation) and the means (faith) together constitute the ground of the free justification.</p>',
    "25": '<p><strong>ἱλαστήριον</strong> (<em>hilastērion</em>) — the most debated single term in Romans. Three primary options: (1) the mercy seat (<em>kapporeth</em>) of Exod 25:17-22 and Lev 16, where the LXX uses this exact word — making Christ the place where God and humanity meet in the blood-applied atonement; (2) a propitiatory sacrifice (the sin-covering/guilt-removing offering); (3) a means of expiation (removing the defilement of sin without the propitiation element). The mercy seat background has the advantage of being the LXX term and providing a spatial-priestly image: Christ is both the priest and the meeting-place of divine presence and human need.</p><p><strong>ἐν τῇ ἀνοχῇ τοῦ θεοῦ</strong> (<em>en tē anochē tou theou</em>) — "in the forbearance of God" — the same word as 2:4; divine patience during the period of prior sins was not moral indifference but the postponement of the full accounting until the cross. The OT sacrificial system operated on "credit" secured by the coming atonement.</p>',
    "26": '<p><strong>εἰς τὸ εἶναι αὐτὸν δίκαιον καὶ δικαιοῦντα τὸν ἐκ πίστεως Ἰησοῦ</strong> (<em>eis to einai auton dikaion kai dikaiounta ton ek pisteōs Iēsou</em>) — "so that he might be just and the justifier of the one who has faith in Jesus." The pair <em>dikaion kai dikaiounta</em> resolves the divine dilemma: the cross satisfies the demand of God\'s holiness (he remains just) while simultaneously enabling the acquittal of the ungodly (he is the justifier). Without the cross, God could be just or merciful but not both simultaneously; the atonement is the resolution of this tension in Paul\'s theology.</p>',
    "27": '<p><strong>διὰ ποίου νόμου;</strong> (<em>dia poiou nomou;</em>) — "through what kind of law?" — the unexpected use of <em>nomos</em> for the "law of faith" is a wordplay: the law of works and the law of faith are both <em>nomoi</em> (principles) but of opposite character. Faith as a <em>nomos</em> excludes boasting by its very nature — it credits what is given, not what is earned. <strong>ἐξεκλείσθη</strong> (<em>exekleisthē</em>) — aorist passive: boasting has been definitively shut out, excluded (from the same root as the shutting of every mouth in v19).</p>',
    "28": '<p><strong>λογιζόμεθα γὰρ δικαιοῦσθαι πίστει ἄνθρωπον</strong> (<em>logizometha gar dikaiousthai pistei anthrōpon</em>) — "for we reckon that a person is justified by faith." <em>Logizometha</em> (present middle: we are reckoning, we count it as established) is the same forensic-accounting verb that governs the whole argument of ch4. <strong>χωρὶς ἔργων νόμου</strong> — "apart from works of law" — Paul will add "alone" by implication; Luther\'s famous <em>sola fide</em> translation ("by faith alone") is a legitimate interpretive rendering of the <em>choris ergōn nomou</em> exclusion.</p>',
    "29": '<p><strong>ἢ Ἰουδαίων ὁ θεὸς μόνον;</strong> (<em>ē Ioudaiōn ho theos monon;</em>) — "or is God the God of Jews only?" — the rhetorical question surfaces the implication of the faith-principle: a God who justifies by faith (rather than by ethnic-covenant membership) is by definition a God of all peoples who believe. The monotheism of v30 ("since God is one") is the theological ground of the universality of faith-justification.</p>',
    "30": '<p><strong>εἴπερ εἷς ὁ θεός</strong> (<em>eiper heis ho theos</em>) — "since indeed God is one" — the Shema (Deut 6:4 — <em>yhwh echad</em>) is the ground of Paul\'s argument for universal salvation by faith. One God means one way of right-standing before that God — faith — applicable to Jew and Gentile alike. The monotheism of Israel\'s confession becomes the basis for the universality of the gospel.</p>',
    "31": '<p><strong>νόμον οὖν καταργοῦμεν διὰ τῆς πίστεως;</strong> (<em>nomon oun katargoumen dia tēs pisteōs;</em>) — "do we therefore nullify the law through faith?" — <em>katargeō</em> (render inoperative) — the anticipated objection after ch3\'s argument. Paul\'s denial is emphatic: <strong>μὴ γένοιτο· ἀλλὰ νόμον ἱστάνομεν</strong> — "by no means! On the contrary, we establish the law." <em>Histanomen</em> (we establish/uphold) — faith does not abolish the law but fulfills the purpose the law was always pointing toward, and confirms the law\'s own testimony (3:21 — the law and prophets witnessed to this righteousness).</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 1–3 mkt-original written.')

if __name__ == '__main__':
    main()
